const templates = [
  {
    type: 'tool-giveaway',
    prompt: 'Write a tweet about a free AI productivity app called XPLife. Hook: "I built an AI app that turns your boring to-do list into an RPG..." Make people curious. End with: Try it free → xplife.app'
  },
  {
    type: 'cheat-sheet',
    prompt: 'Write a tweet sharing a productivity cheat sheet. Hook: "I gamified my entire life and here\'s what happened after 30 days:" List 3 specific results (tasks completed, streaks, level ups). End with: Free at xplife.app'
  },
  {
    type: 'case-study',
    prompt: 'Write a tweet as a mini case study. Hook: "Traditional to-do apps have a 92% abandonment rate. RPG quest systems have 3x better retention. So I combined them." Share the concept of XPLife. End with: xplife.app'
  },
  {
    type: 'adhd-focus',
    prompt: 'Write a tweet for people with ADHD or focus issues. Hook: "ADHD brain + regular to-do list = disaster. ADHD brain + RPG quest system = unstoppable." Explain how gamification helps with dopamine and motivation. End with: Built for brains like ours → xplife.app'
  },
  {
    type: 'neuroscience',
    prompt: 'Write a tweet about the neuroscience behind XPLife. Hook: "Your brain releases dopamine when you level up in games. I hacked this for real-life productivity." Explain the Braverman personality system briefly. End with: Discover your type → xplife.app'
  },
  {
    type: 'social-proof',
    prompt: 'Write a tweet with social proof angle. Hook: "People keep asking how I stay consistent with my goals. My secret: I turned everything into quests with XP rewards." Share specific benefits (streaks, levels, AI-generated tasks). End with: Join free → xplife.app'
  },
  {
    type: 'comparison',
    prompt: 'Write a tweet comparing old vs new approach. Hook: "2024: Write tasks on sticky notes, forget them by lunch. 2026: AI generates personalized RPG quests based on your brain chemistry." Make it punchy and visual. End with: The future is free → xplife.app'
  }
];

const today = new Date();
const hour = today.getUTCHours();
const dayIndex = today.getDate();

// Morning = even templates, Evening = odd templates
const filteredIndices = hour < 15
  ? [0, 2, 4, 6]
  : [1, 3, 5];

const pick = filteredIndices[dayIndex % filteredIndices.length];
const template = templates[pick];

return [{
  json: {
    templateType: template.type,
    prompt: template.prompt,
    timeContext: hour < 15 ? 'morning motivation' : 'evening insight',
    dayOfWeek: ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][today.getDay()]
  }
}];

const content = $input.first().json.message?.content || $input.first().json.text || '';
let tweet = content.trim();

// Remove wrapping quotes if AI added them
if ((tweet.startsWith('"') && tweet.endsWith('"')) || (tweet.startsWith("'") && tweet.endsWith("'"))) {
  tweet = tweet.slice(1, -1);
}

// Safety: truncate to 280 chars
if (tweet.length > 280) {
  tweet = tweet.substring(0, 277) + '...';
}

return [{ json: { tweet, charCount: tweet.length } }];
